member.example:
Bind the SphereCollider radius property using a serialized binder field — the target SphereCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SphereColliderRadiusBinder _radius;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _radius;
    }


Bind the SphereCollider radius property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private SphereCollider _sphereCollider;
        
        private SphereColliderRadiusBinder Radius =>
            new(_sphereCollider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _radius;
    }

Switch the SphereCollider radius between two float values using a serialized binder field — the target SphereCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SphereColliderRadiusSwitcherBinder _isExpanded;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }


Switch the SphereCollider radius between two float values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private SphereCollider _sphereCollider;
        
        private SphereColliderRadiusSwitcherBinder IsExpanded => new(
            _sphereCollider,
            trueValue: 1f,
            falseValue: 0.5f);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }
